import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import './App.css';
import { useInView } from 'react-intersection-observer';
import { BrowserRouter as Router, Route, Routes, useNavigate } from 'react-router-dom';

// Ensure BASE_URL is defined using the environment variable or fallback to a default
const BASE_URL = process.env.REACT_APP_API_BASE_URL || 'http://127.0.0.1:5000';

function App() {
  const [scenes, setScenes] = useState([]);
  const [selectedVideoInfo, setSelectedVideoInfo] = useState(null);
  const navigate = useNavigate();
  const [uniqueVideoIDs, setUniqueVideoIDs] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false); // Add state to track modal open/close

  useEffect(() => {
    // Fetch scenes - Correctly use template literals with backticks
    axios.get(`${BASE_URL}/scenes`)
      .then(response => {
        setScenes(shuffleArray(response.data)); // Assuming this endpoint returns all scenes
      })
      .catch(error => {
        console.error('Error fetching scenes: ', error);
      });

    // Fetch videos for the menu - Correctly use template literals with backticks
    axios.get(`${BASE_URL}/videos`)
      .then(response => {
        setUniqueVideoIDs(response.data); // Assuming this endpoint returns unique videos
      })
      .catch(error => {
        console.error('Error fetching videos: ', error);
      });
  }, []); // The empty dependency array ensures this runs only once on mount

  const handleVideoNameClick = (videoID) => {
    if (!isModalOpen) { // Check if a modal is open before fetching new data
      // Fetch detailed video information using the correct relative endpoint
      axios.get(`${BASE_URL}/video_info/${videoID}`)
          .then(response => {
              setSelectedVideoInfo(response.data);
              navigate(`/videos/${videoID}`);
          })
          .catch(error => {
              console.error('Error fetching video info: ', error);
          });
    }
  };

  const handleCloseModal = () => {
    setSelectedVideoInfo(null);
    navigate('/');
    setIsModalOpen(false); // Close the modal and allow fetching data again
  };

  function shuffleArray(array) {
    for (let i = array.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [array[i], array[j]] = [array[j], array[i]];
    }
    return array;
  }

  const Video = ({ src, videoID, onVideoClick }) => {
    const videoRef = useRef(null);
    const { ref, inView } = useInView({
      triggerOnce: true,
      rootMargin: '50px 0px',
    });

    const handleMouseEnter = () => {
      if (videoRef.current) videoRef.current.play();
    };

    const handleMouseLeave = () => {
      if (videoRef.current) videoRef.current.pause();
    };

    return (
      <div ref={ref} style={{ width: '100%', height: 'auto' }}>
        {inView && (
          <video
            ref={videoRef}
            src={src}
            loop
            muted
            playsInline
            onClick={() => {
              onVideoClick(videoID);
              setIsModalOpen(true); // Open the modal when clicking a video
            }}
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
            style={{ width: '100%', height: 'auto' }}
          />
        )}
      </div>
    );
  };

  return (
    <div className="App">
      <div className="video-menu">
        {uniqueVideoIDs.map(({ videoID, videoName }) => (
          <div key={videoID} onClick={() => handleVideoNameClick(videoID)}>
            {videoName}
          </div>
        ))}
      </div>
      <div className="video-grid">
        {scenes.map(scene => (
          <Video
            key={scene.sceneURL}
            src={scene.sceneURL}
            videoID={scene.videoID}
            onVideoClick={() => handleVideoNameClick(scene.videoID)}
          />
        ))}
      </div>
      {selectedVideoInfo && <Modal videoInfo={selectedVideoInfo} onClose={handleCloseModal} />}
    </div>
  );
}

function AppWrapper() {
  return (
    <Router>
      <Routes>
        <Route path="/videos/:videoID" element={<App />} />
        <Route path="/" element={<App />} />
      </Routes>
    </Router>
  );
}

export default AppWrapper;
